mapper.insert:
INSERT INTO USER_PRIVACY (
USER_ID, CI, NAME, PHONE_NUMBER, BIRTH_DATE, UPDATED_AT
) VALUES (
#{userId}, #{ci}, #{name}, #{phoneNumber}, #{birthDate},
CURRENT_TIMESTAMP
)

mapper.update:
UPDATE USERS
SET NICKNAME = #{nickname}
WHERE USER_ID = #{userId}

UPDATE USERS u
SET u.PASSWORD = #{encodePW}
WHERE u.USER_ID = (
SELECT p.USER_ID
FROM USER_PRIVACY p
WHERE p.NAME = #{name}
AND p.BIRTH_DATE = #{birth}
)

UPDATE USER_ACCOUNTS
SET CUSTOMER_UID = #{customerUid}
WHERE USER_ID = #{userId}
AND IS_PRIMARY = 'Y'

UPDATE USER_ACCOUNTS
SET STATUS = 'DELETE'
WHERE ACCOUNT_ID = #{accountId}

UPDATE GROUPS
SET GROUP_NAME = #{groupName}
WHERE GROUP_ID = #{groupId}

UPDATE USER_ACCOUNTS
SET BALANCE = BALANCE + #{amount}
WHERE USER_ID = #{userId} AND STATUS = 'ACTIVE'

mapper.insert:
INSERT INTO TRANSACTION_HISTORY (
TRANSACTION_ID, USER_ID, GROUP_ID, AMOUNT, DESCRIPTION, CREATED_AT
) VALUES (
seq_transaction.NEXTVAL, #{userId}, #{groupId}, #{amount}, '모임 종료 정산',
CURRENT_TIMESTAMP
)

mapper.update:
UPDATE USER_ACCOUNTS
SET BALANCE = BALANCE - #{amount}
WHERE ACCOUNT_NUMBER = #{accountNumber}
AND BALANCE >= #{amount}

UPDATE USER_ACCOUNTS
SET BALANCE = BALANCE + #{amount}
WHERE ACCOUNT_NUMBER = #{accountNumber}

UPDATE USER_ACCOUNTS
SET IS_PRIMARY = 'Y'
WHERE ACCOUNT_ID = #{accountId}
AND USER_ID = #{userId}
AND STATUS = 'ACTIVE'

mapper.select:
SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM USER_ACCOUNTS
WHERE ACCOUNT_NUMBER = #{accountNumber}

SELECT ACCOUNT_ID
FROM USER_ACCOUNTS
WHERE ACCOUNT_NUMBER = #{accountNumber}
  AND USER_ID = #{userId}
  AND STATUS = 'ACTIVE'
